settings.custom_liquid:
{%- comment -%}
  BFC — Contact / Visit (Liquid snippet, no schema)
{%- endcomment -%}

<style>
  .bfc-contact-page{
    max-width: 1100px;
    margin: 0 auto;
    padding: 48px 20px;
  }
  .bfc-contact-page h1{ margin: 0 0 20px 0; }
  .bfc-contact-grid{
    display:grid;
    grid-template-columns:1fr;
    gap:18px;
    margin:18px 0 28px 0;
  }
  @media (min-width: 860px){
    .bfc-contact-grid{ grid-template-columns:1fr 1fr; gap:22px; }
  }
  .bfc-card{
    border: 1px solid rgba(0,0,0,0.12);
    padding: 18px;
    background:#fff;
  }
  .bfc-card h2{ margin:0 0 10px 0; font-size:20px; }
  .bfc-kv{ display:grid; gap:10px; margin:0; }
  .bfc-kv div{ display:grid; gap:3px; }
  .bfc-label{
    font-size:12px;
    letter-spacing:0.02em;
    opacity:0.75;
    text-transform:uppercase;
  }
  .bfc-value a{ text-decoration:underline; text-underline-offset:2px; }
  .bfc-note{ margin-top:10px; font-size:14px; opacity:0.85; }

  .bfc-dept{
    border-top: 1px solid rgba(0,0,0,0.10);
    padding-top: 14px;
    margin-top: 14px;
  }
  .bfc-dept h3{ margin:0 0 10px 0; font-size:16px; }
  .bfc-dept ul{
    list-style:none;
    padding:0;
    margin:0;
    display:grid;
    gap:10px;
  }
  .bfc-dept li{ display:grid; gap:2px; font-size:16px; }

  .bfc-map{
    margin-top: 18px;
    display: inline-block;
    border: 1px solid #000;
    padding: 10px 14px;
    text-decoration:none;
  }
</style>

<div class="bfc-contact-page">
  <h1>Contact &amp; Visit</h1>

  <div class="bfc-contact-grid">

    <!-- Contact Us -->
    <div class="bfc-card">
      <h2>Contact Us</h2>

      <div class="bfc-kv">
        <div>
          <div class="bfc-label">Phone</div>
          <div class="bfc-value">
            <a href="tel:+18452613573">845-261-3573</a>
          </div>
        </div>

        <div>
          <div class="bfc-label">General Email</div>
          <div class="bfc-value">
            <a href="mailto:hello@brooklynfilmcamera.com">hello@brooklynfilmcamera.com</a>
          </div>
        </div>
      </div>

      <!-- Departments -->
      <div class="bfc-dept">
        <h3>Department Emails</h3>
        <ul>
          <li>
            <div class="bfc-label">Repairs</div>
            <div class="bfc-value">
              <a href="mailto:repairs@brooklynfilmcamera.com">repairs@brooklynfilmcamera.com</a>
            </div>
          </li>
          <li>
            <div class="bfc-label">SX-70 Restoration</div>
            <div class="bfc-value">
              <a href="mailto:sx70@brooklynfilmcamera.com">sx70@brooklynfilmcamera.com</a>
            </div>
          </li>
          <li>
            <div class="bfc-label">Events</div>
            <div class="bfc-value">
              <a href="mailto:hannah@brooklynfilmcamera.com">hannah@brooklynfilmcamera.com</a>
            </div>
          </li>
          <li>
            <div class="bfc-label">Wholesale</div>
            <div class="bfc-value">
              <a href="mailto:shanna@brooklynfilmcamera.com">shanna@brooklynfilmcamera.com</a>
            </div>
          </li>
          <li>
            <div class="bfc-label">Operational Manager</div>
            <div class="bfc-value">
              <a href="mailto:griffin@brooklynfilmcamera.com">griffin@brooklynfilmcamera.com</a>
            </div>
          </li>
          <li>
            <div class="bfc-label">Developing</div>
            <div class="bfc-value">
              <a href="mailto:developing@brooklynfilmcamera.com">developing@brooklynfilmcamera.com</a>
            </div>
          </li>
        </ul>

        <p class="bfc-note">
          Not sure who to email? Start with 
          <a href="mailto:hello@brooklynfilmcamera.com">hello@brooklynfilmcamera.com</a> 
          and we'll route you.
        </p>
      </div>
    </div>

    <!-- Visit Us -->
    <div class="bfc-card">
      <h2>Visit Us</h2>

      <div class="bfc-kv">
        <div>
          <div class="bfc-label">Address</div>
          <div class="bfc-value">
            855 Grand Street<br>
            Brooklyn, NY 11211
          </div>
        </div>

        <div>
          <div class="bfc-label">Hours</div>
          <div class="bfc-value">Every Day 11–8</div>
          <div class="bfc-note">
            * Holiday Closures: Thanksgiving, Christmas Eve (12/24), Christmas Day (12/25)
          </div>
        </div>
      </div>

      {%- assign bfc_maps_query = '855 Grand Street Brooklyn NY 11211' | url_encode -%}
      <a class="bfc-map" href="https://www.google.com/maps/search/?api=1&query={{ bfc_maps_query }}" target="_blank" rel="noopener">
        Open in Google Maps
      </a>
    </div>

  </div>

  <!-- About / Neighborhood copy -->
  <div class="bfc-card">
    <h2>About Brooklyn Film Camera</h2>

    <div style="font-size:16px; line-height:1.6;">
      <p style="margin:0 0 12px 0;">
        Brooklyn Film Camera is a camera shop, project space, and gallery in NYC that sells a wide variety of film photography cameras, common and rare films, and new product solutions for modern film shooters. One of just a few remaining places in the world still offering expert restoration services for vintage Polaroid cameras, Brooklyn Film Camera serves as a community hub for film photographers and is constantly buzzing with classes, workshops, art shows, screenings, and more.
      </p>

      <p style="margin:0;">
        Our space is located in beautiful Bushwick, Brooklyn immediately next to the Grand Street L-Train Subway Station. Plenty of great coffee shops, bars, restaurants, and retail shops are just minutes from our front door.&nbsp;Enjoying and photographing the neighborhood is one of our favorite activities, and we'd encourage you to do the same when you come to visit.&nbsp;We hope to see you soon!
      </p>
    </div>
  </div>
</div>
